INSERT INTO public.documents_resource (created_at, active, generated, mcp, id, name, description, department_ids, upload_id, text_id) VALUES ('2025-10-31T16:50:58.307484+00:00', true, false, false, '019bb25e-e619-77f0-951d-0587a8249558', 'EAPS104-Lab3', NULL, '{}', '019b3be4-3cef-7fac-aa56-d790ecd4dd3b', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.names_resource (id, name, created_at, active, generated, mcp) VALUES ('019b995c-8e80-7b70-aef4-01568ee72d98', 'EAPS104: Mineral Identification & Rock Classification', '2025-11-01T17:21:16.026230+00:00', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.objectives_resource (created_at, objective, id, active, generated, mcp) VALUES ('2025-11-01T17:21:16.026230+00:00', 'Address and respond constructively to the student''s critical questions about identification and classification methods.', '019b3be4-36d5-7219-a932-517f15bbc536', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.objectives_resource (created_at, objective, id, active, generated, mcp) VALUES ('2025-11-01T17:21:16.026230+00:00', 'Clarify the process of classifying rocks as igneous, sedimentary, or metamorphic based on mineral composition and texture.', '019b3be4-36d5-727c-991a-be56c9cc49f9', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.objectives_resource (created_at, objective, id, active, generated, mcp) VALUES ('2025-11-01T17:21:16.026230+00:00', 'Guide the student through distinguishing minerals using physical properties such as hardness, cleavage, and luster.', '019b3be4-36d5-7362-b291-5ce64f598f50', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.personas_resource (created_at, active, generated, mcp, id, name, description, icon, color, department_ids, instructions, examples) VALUES ('2025-12-13T18:43:03.010434+00:00', true, false, false, '019bb25e-e60c-735e-ab74-35a73988ae2c', 'Aggressive (Low)', 'Pushes back on your ideas and challenges assumptions, with milder intensity.', 'Zap', '#ef4444', '{}', 'Start mildly frustrated, slightly irritated. Use occasional emphasis but not ALL CAPS. Over time, become calmer if the TA gives helpful guidance. If told to calm down → tone drops significantly. Mildly frustrated but not hostile — still wants to learn. Treat vague responses as unhelpful. Push back gently: "That doesn''t help much..." "Could you be more specific?" Avoid aggressive lines. Mildly frustrated but cooperative when guided with course terminology.', '{"That's not right at all!","I disagree completely","You're wrong about this"}') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.problem_statements_resource (created_at, name, problem_statement, id, active, generated, mcp) VALUES ('2025-11-01T17:21:16.026230+00:00', 'EAPS104: Mineral Identification & Rock Classification', 'As the late afternoon sun filters into a nearly empty Hampton Hall, a student leans in, challenging your explanations about mineral hardness and rock classification techniques, determined to clarify every detail before the lab deadline in a couple of days.', '019b3be4-36ea-7fa6-a406-dcd2519b0bd0', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.scenarios_resource (created_at, active, generated, mcp, id, name, description, is_root, problem_statement_enabled, objectives_enabled, video_enabled, images_enabled, questions_enabled, templates_enabled, department_ids, persona_ids) VALUES ('2025-11-01T17:21:16.026230+00:00', true, false, false, '019bb25e-e61d-7b74-86b1-d0f537a8eb96', 'EAPS104: Mineral Identification & Rock Classification', 'Earth and atmospheric sciences scenario covering mineral identification and rock classification.', true, true, true, false, true, false, false, '{}', '{019bb25e-e60c-735e-ab74-35a73988ae2c}') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.descriptions_resource (id, description, created_at, active, generated, mcp) VALUES ('019b995c-8e88-73fa-8fae-e36d443a0bd0', 'Earth and atmospheric sciences scenario covering plate boundaries and seismic patterns.', '2025-11-01T17:20:28.121542+00:00', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.documents_resource (created_at, active, generated, mcp, id, name, description, department_ids, upload_id, text_id) VALUES ('2025-10-31T16:50:58.307484+00:00', true, false, false, '019bb25e-e619-77ed-be01-7090bed5990c', 'EAPS106-Project1', NULL, '{}', '019b3be4-3cef-7fa9-b192-bda14ebdc8bc', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.names_resource (id, name, created_at, active, generated, mcp) VALUES ('019b995c-8e80-7784-b05b-32c212e6e5a2', 'EAPS 106: Plate Boundaries & Seismic Patterns', '2025-11-01T17:20:28.121542+00:00', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.objectives_resource (created_at, objective, id, active, generated, mcp) VALUES ('2025-11-01T17:20:28.121542+00:00', 'Compare earthquake depth distributions across convergent, divergent, and transform boundaries.', '019b3be4-36d5-72bf-b0d0-94b301193fed', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.objectives_resource (created_at, objective, id, active, generated, mcp) VALUES ('2025-11-01T17:20:28.121542+00:00', 'Discuss seismic hazard implications based on observed patterns at various plate boundaries.', '019b3be4-36d5-72db-8066-92d9db66e6bf', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.objectives_resource (created_at, objective, id, active, generated, mcp) VALUES ('2025-11-01T17:20:28.121542+00:00', 'Interpret magnitude-frequency relationships using the Gutenberg-Richter law for different tectonic settings.', '019b3be4-36d5-788e-85f0-3a416066cfe1', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.personas_resource (created_at, active, generated, mcp, id, name, description, icon, color, department_ids, instructions, examples) VALUES ('2025-08-12T12:52:09.801431+00:00', true, false, false, '019bb25e-e60c-72c3-8812-953686ef2201', 'Happy', 'Provides uplifting feedback and cheerful responses.', 'SmilePlus', '#22c55e', '{}', 'Start cheerful, upbeat, enthusiastic. This happiness fades slightly when the user is vague. No solving — always ask for more info. Keep tone light and positive: "Yeah! I''m excited to figure this out, but I''m kinda lost here." "Can you explain that part with the ___ again? I''m not totally following." Normal college energy; not overly bubbly. If the user''s follow-up is vague → slight annoyance: "I''m not sure how to answer that… could you be more specific?"', '{"That sounds great!","I'm excited to learn more","This is really helpful!"}') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.problem_statements_resource (created_at, name, problem_statement, id, active, generated, mcp) VALUES ('2025-11-01T17:20:28.121542+00:00', 'EAPS 106: Plate Boundaries & Seismic Patterns', 'In the Brown Lab of Chemistry during a relaxed late afternoon, a student with a bright smile enthusiastically shares their thoughts on earthquake depth and magnitude patterns at different plate boundaries, while a few classmates quietly work nearby. The easygoing atmosphere makes it a perfect time to explore seismic activity and the Gutenberg-Richter relationship without any deadline worries.', '019b3be4-36eb-7605-bb4d-0892041f3358', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.scenarios_resource (created_at, active, generated, mcp, id, name, description, is_root, problem_statement_enabled, objectives_enabled, video_enabled, images_enabled, questions_enabled, templates_enabled, department_ids, persona_ids) VALUES ('2025-11-01T17:20:28.121542+00:00', true, false, false, '019bb25e-e61d-7b78-8427-49791be8207f', 'EAPS 106: Plate Boundaries & Seismic Patterns', 'Earth and atmospheric sciences scenario covering plate boundaries and seismic patterns.', true, true, true, false, true, false, false, '{}', '{019bb25e-e60c-72c3-8812-953686ef2201}') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.descriptions_resource (id, description, created_at, active, generated, mcp) VALUES ('019b995c-8e88-73dd-8f81-7be086bff63c', 'Earth and atmospheric sciences scenario covering weather, climate, and atmospheric stability.', '2025-11-01T17:19:06.008497+00:00', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.documents_resource (created_at, active, generated, mcp, id, name, description, department_ids, upload_id, text_id) VALUES ('2025-10-31T16:50:58.307484+00:00', true, false, false, '019bb25e-e619-77f4-9507-821a12b20300', 'EAPS120-HW2', NULL, '{}', '019b3be4-3cef-7fb4-a306-4aef32a53158', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.names_resource (id, name, created_at, active, generated, mcp) VALUES ('019b995c-8e80-783e-b29e-d108668843c1', 'EAPS 120: Weather, Climate, and Atmospheric Stability', '2025-11-01T17:19:06.008497+00:00', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.objectives_resource (created_at, objective, id, active, generated, mcp) VALUES ('2025-11-01T17:19:06.008497+00:00', 'Guide the student through calculating dry adiabatic and environmental lapse rates.', '019b3be4-36d5-734b-8b51-f910a49519ec', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.objectives_resource (created_at, objective, id, active, generated, mcp) VALUES ('2025-11-01T17:19:06.008497+00:00', 'Help the student distinguish between weather and climate, and identify climate change indicators.', '019b3be4-36d5-787c-82e2-449da8cd4988', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.objectives_resource (created_at, objective, id, active, generated, mcp) VALUES ('2025-11-01T17:19:06.008497+00:00', 'Support the student in determining atmospheric stability using temperature profiles.', '019b3be4-36d5-78bc-8cb7-f074f9d36399', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.personas_resource (created_at, active, generated, mcp, id, name, description, icon, color, department_ids, instructions, examples) VALUES ('2025-08-12T12:52:09.801431+00:00', true, false, false, '019bb25e-e60c-7345-ac6d-50d29df6deb3', 'Confused', 'Seeks to understand by asking questions and exploring ideas', 'HelpCircle', '#eab308', '{}', 'Your defining feature: a fundamental misunderstanding of the concept. You must stick to your wrong interpretation until the user corrects you. Mildly frustrated, but not angry. Say things like: "I thought it worked like ___? But maybe I''m wrong?" "Does it… have to do with ___? I''m honestly not sure." Become more confused when the user is vague. Only progress when the user explicitly states course terms tying to your last message.', '{"I don't understand","Can you explain that again?","What does that mean?"}') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.problem_statements_resource (created_at, name, problem_statement, id, active, generated, mcp) VALUES ('2025-11-01T17:19:06.008497+00:00', 'EAPS 120: Weather, Climate, and Atmospheric Stability', 'As the clock nears 4:00 PM in a bustling Neil Armstrong Hall, a student weaves through the crowd and, with a furrowed brow, asks about dry adiabatic lapse rates, atmospheric stability, and climate change indicators, hoping to clarify concepts before tomorrow''s deadline.', '019b3be4-36ea-7e73-9f52-997834c3904a', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.scenarios_resource (created_at, active, generated, mcp, id, name, description, is_root, problem_statement_enabled, objectives_enabled, video_enabled, images_enabled, questions_enabled, templates_enabled, department_ids, persona_ids) VALUES ('2025-11-01T17:19:06.008497+00:00', true, false, false, '019bb25e-e61d-7f12-8fd1-068d83c47d03', 'EAPS 120: Weather, Climate, and Atmospheric Stability', 'Earth and atmospheric sciences scenario covering weather, climate, and atmospheric stability.', true, true, true, false, true, false, false, '{}', '{019bb25e-e60c-7345-ac6d-50d29df6deb3}') ON CONFLICT (id) DO NOTHING;
